@app.get("/api/search")
def search_products():
    q = request.args.get("q", "", type=str)
    size = request.args.get("size", SEARCH_SIZE, type=int)

    q = normalize_query(q)

    if not q:
        raise BadRequest("Missing required query parameter: q")

    if len(q) < SEARCH_MIN_QUERY_LEN:
        raise BadRequest(f"Query parameter q must be at least {SEARCH_MIN_QUERY_LEN} character(s)")

    if size < 1:
        raise BadRequest("size must be greater than 0")

    size = min(size, SEARCH_MAX_SIZE)

    es = get_es_client()
    body = build_search_query(q, size)

    try:
        resp = es.search(index=ES_INDEX, body=body)
        hits = resp.get("hits", {}).get("hits", [])
        products = []
        for hit in hits:
            source = hit.get("_source", {})
            source["score"] = hit.get("_score")
            products.append(source)

        return jsonify({
            "query": q,
            "count": len(products),
            "products": products
        }), 200

    except (ESConnectionError, TransportError) as exc:
        logger.exception("Elasticsearch search failed")
